import jinja2
import re

SAFE_SYSTEM_PROMPT_VARIABLES = frozenset({"user_name", "session_id", "current_date"})

def render_system_prompt(template: str, variables: dict[str, str]) -> str:
    """
    Render the system prompt template safely.
    Only allow whitelisted variables; reject template syntax in values.
    """
    # Reject any variables not in the allowlist
    for key in variables:
        if key not in SAFE_SYSTEM_PROMPT_VARIABLES:
            raise ValueError(f"Disallowed variable in system prompt: {key!r}")

    # Reject Jinja2/template syntax in variable values (SSTI guard)
    for key, val in variables.items():
        if re.search(r"\{\{|\{%|\$\{", val):
            raise ValueError(f"Template syntax detected in variable {key!r}: rejected")

    env = jinja2.Environment(autoescape=True)
    tmpl = env.from_string(template)
    return tmpl.render(**variables)

import hashlib
from pathlib import Path

def compute_model_hash(weights_path: Path) -> str:
    """Compute SHA-256 of model weights file for supply chain verification."""
    sha256 = hashlib.sha256()
    with weights_path.open("rb") as f:
        for chunk in iter(lambda: f.read(65536), b""):
            sha256.update(chunk)
    return sha256.hexdigest()

KNOWN_GOOD_HASHES: dict[str, str] = {
    "model-v1.0.bin": "abc123...",   # populated at release time
}

def verify_model_integrity(weights_path: Path) -> bool:
    expected = KNOWN_GOOD_HASHES.get(weights_path.name)
    if expected is None:
        print(f"[SECURITY] No known-good hash for {weights_path.name} — unverified")
        return False
    actual = compute_model_hash(weights_path)
    if actual != expected:
        raise RuntimeError(
            f"Model weight hash mismatch for {weights_path.name}: "
            f"expected {expected[:16]}... got {actual[:16]}..."
        )
    return True
